import{SceneManager}from"./SceneManager.js";import{CombatScene}from"../scenes/CombatScene.js";class Game{constructor(e){this.canvas=document.getElementById(e),this.ctx=this.canvas.getContext("2d"),this.sceneManager=new SceneManager(this),this.lastFrameTime=0}start(){this.sceneManager.changeScene(CombatScene),this.lastFrameTime=performance.now(),requestAnimationFrame(e=>this.gameLoop(e))}gameLoop(e){var t=e-this.lastFrameTime;this.lastFrameTime=e,t=Math.min(t,100),this.update(t),this.render(t),requestAnimationFrame(e=>this.gameLoop(e))}update(e){this.sceneManager.currentScene&&this.sceneManager.currentScene.update(e)}render(e){this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height),this.sceneManager.currentScene&&this.sceneManager.currentScene.render(this.ctx,e)}}export{Game};